        metal: '#1a1a24',
        highlight: '#666680',
        shadow: '#020203',
        reedDark: '#0a0a0f',
        reedLight: '#3a3a4a'
      }
    };

    // Draw a single coin frame onto a canvas
    function drawCoin(ctx, width, height, t, materialName) {
      const mat = MATERIALS[materialName] || MATERIALS.gold;

      // Clear with transparent/subtle backdrop
      ctx.clearRect(0, 0, width, height);

      const centerX = width / 2;
      const centerY = height / 2;
      const radius = Math.min(width, height) * 0.38; // Keep coin safely away from edges

      // Calculate 3D rotation angles based on parameter t [0, 1]
      // We want a full rotation about Y (vertical) and a flip about X (horizontal)
      const angleY = t * Math.PI * 2;
      const angleX = Math.sin(t * Math.PI * 2) * 0.4; // Wobble/flip effect

      // Normal vector of the coin face
      const nx = Math.sin(angleY) * Math.cos(angleX);
      const ny = Math.sin(angleX);
      const nz = Math.cos(angleY) * Math.cos(angleX);

      // Determine which face is showing
      const isFront = nz >= 0;

      // Scale factors for projection
      const scaleX = Math.cos(angleY);
      const scaleY = Math.cos(angleX);

      // Light source direction (fixed in camera space, slightly top-left-front)
      const lx = -0.5;
      const ly = -0.5;
      const lz = 0.707;

      // Calculate diffuse and specular lighting factors
      const dotProduct = nx * lx + ny * ly + nz * lz;
      const diffuse = Math.max(0.2, (dotProduct + 1) / 2);

      // Specular highlight (moves across the surface as it rotates)
      // Reflection vector: R = 2 * (N . L) * N - L
      const rx = 2 * dotProduct * nx - lx;
      const ry = 2 * dotProduct * ny - ly;
      const rz = 2 * dotProduct * nz - lz;
      // Specular intensity based on reflection pointing towards viewer (0, 0, 1)
      const specPower = 12;
      const specular = Math.pow(Math.max(0, rz), specPower);

      ctx.save();
      ctx.translate(centerX, centerY);
      ctx.rotate(angleX); // Apply the horizontal tilt

      // 1. Draw Reeded Edge (visible when coin is turned sideways)
      const edgeThickness = radius * 0.12;
      const visibleEdge = Math.abs(scaleX) < 0.98;

      if (visibleEdge) {
        const steps = 60;
        const edgeDirection = scaleX > 0 ? -1 : 1;

        for (let i = 0; i < steps; i++) {
          const stepAngle = (i / steps) * Math.PI - Math.PI / 2;
          const x = Math.sin(stepAngle) * radius * scaleX;
          const y = Math.cos(stepAngle) * radius;

          // Thickness offset
          const ox = edgeThickness * Math.abs(scaleX) * edgeDirection;

          // Alternate colors for reeded ridges
          const isRidge = i % 2 === 0;
          ctx.strokeStyle = isRidge ? mat.reedLight : mat.reedDark;
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(x, y);
          ctx.lineTo(x + ox, y);
          ctx.stroke();
        }
      }

      // 2. Draw Main Coin Disc
      ctx.save();
      ctx.scale(scaleX, 1);

      // Base metal gradient
      const grad = ctx.createRadialGradient(-radius*0.3, -radius*0.3, 0, 0, 0, radius);
      grad.addColorStop(0, mat.highlight);
      grad.addColorStop(0.3, mat.metal);
      grad.addColorStop(0.8, mat.base);
      grad.addColorStop(1, mat.shadow);

      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(0, 0, radius, 0, Math.PI * 2);
      ctx.fill();

      // Outer Rim
      ctx.strokeStyle = mat.highlight;
      ctx.lineWidth = radius * 0.04;
      ctx.stroke();

      // Inner Rim
      ctx.strokeStyle = mat.shadow;
      ctx.lineWidth = radius * 0.02;
      ctx.beginPath();
      ctx.arc(0, 0, radius * 0.92, 0, Math.PI * 2);
      ctx.stroke();

      // 3. Draw Face Details (Embossing)
      ctx.fillStyle = mat.highlight;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      if (isFront) {
        // FRONT FACE: WastedToken Emblem (WT)
        ctx.shadowColor = mat.shadow;
        ctx.shadowBlur = 4;
        ctx.shadowOffsetX = 2;
        ctx.shadowOffsetY = 2;

        // Draw stylized WT logo
        ctx.font = `bold ${radius * 0.4}px ${getComputedStyle(document.body).fontFamily}`;
        ctx.fillText("WT", 0, -radius * 0.05);

        // Decorative stars or dots
        ctx.font = `${radius * 0.08}px sans-serif`;
        ctx.fillText("★ ★ ★", 0, radius * 0.25);

        // Curved text on rim
        ctx.font = `bold ${radius * 0.07}px sans-serif`;
        ctx.fillText("WASTEDTOKEN MINT", 0, -radius * 0.6);
      } else {
        // BACK FACE: Denomination
        ctx.shadowColor = mat.shadow;
        ctx.shadowBlur = 4;
        ctx.shadowOffsetX = -2; // Reverse shadow direction for back face
        ctx.shadowOffsetY = 2;

        ctx.font = `bold ${radius * 0.22}px sans-serif`;
        ctx.fillText("10,000", 0, -radius * 0.15);

        ctx.font = `bold ${radius * 0.14}px sans-serif`;
        ctx.fillText("TOKENS", 0, radius * 0.1);

        ctx.font = `${radius * 0.07}px sans-serif`;
        ctx.fillText("SECURE • PHYSICAL • PROOF", 0, radius * 0.45);
      }

      ctx.restore(); // End of scaled disc

      // 4. Specular Highlight Overlay (Rakes across the coin surface)
      // We draw a semi-transparent white gradient overlay that simulates light reflection
      ctx.save();
      ctx.scale(scaleX, 1);

      // Calculate highlight position based on rotation
      const highlightX = -scaleX * radius * 0.5;
      const highlightY = -radius * 0.5;

      const specGrad = ctx.createRadialGradient(highlightX, highlightY, 0, highlightX, highlightY, radius * 1.2);
      specGrad.addColorStop(0, `rgba(255, 255, 255, ${specular * 0.6})`);
      specGrad.addColorStop(0.3, `rgba(255, 255, 255, ${specular * 0.2})`);
      specGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');

      ctx.fillStyle = specGrad;
      ctx.beginPath();
      ctx.arc(0, 0, radius * 0.98, 0, Math.PI * 2);
      ctx.fill();

      ctx.restore();

      ctx.restore(); // End of tilted coordinate system
    }

    // --- Animation Loop & API ---
    let globalTime = 0;
    const heroCtx = HERO_CANVAS.getContext('2d');

    function animate(timestamp) {
      if (!isAnimating) return;

      // Loop every 6 seconds
      globalTime = (timestamp % 6000) / 6000;
      drawCoin(heroCtx, HERO_CANVAS.width, HERO_CANVAS.height, globalTime, 'gold');

      // Also animate the static grid canvases slowly to show off their materials
      renderGridCanvases(timestamp);

      animationFrameId = requestAnimationFrame(animate);
    }

    function renderGridCanvases(timestamp) {
      const editions = ['bronze', 'silver', 'gold', 'black'];
      const canvases = document.querySelectorAll('.edition-canvas');

      canvases.forEach((canvas, index) => {
        const ctx = canvas.getContext('2d');
        // Give each tile a slightly offset rotation speed/start
        const t = ((timestamp + index * 1500) % 8000) / 8000;
        drawCoin(ctx, canvas.width, canvas.height, t, editions[index]);
      });
    }

    // Programmatic API
    window.demo = {
      canvas: HERO_CANVAS,
      setTime: function(t) {
        // Ensure t is bounded [0, 1]
        t = Math.max(0, Math.min(1, t));
        // Draw synchronously
        drawCoin(heroCtx, HERO_CANVAS.width, HERO_CANVAS.height, t, 'gold');
      },
      pause: function() {
        isAnimating = false;
        if (animationFrameId) {
          cancelAnimationFrame(animationFrameId);
        }
      }
    };

    // Start animation on load
    requestAnimationFrame(animate);


    // --- UI Interactions ---
    const toast = document.getElementById('toast');
    const buyButtons = document.querySelectorAll('.buy');

    buyButtons.forEach(button => {
      button.addEventListener('click', (e) => {
        const editionName = e.target.closest('.edition').getAttribute('data-edition');
        toast.textContent = `Added ${editionName.toUpperCase()} Edition to cart!`;
        toast.classList.add('show');

        setTimeout(() => {
          toast.classList.remove('show');
        }, 3000);
      });
    });
  </script>
</body>
